#!/usr/bin/env node
/**
 * Copy source-only images into pass_01/unassigned/unclassified/ for /matches review.
 *
 * Uses source-audit-report.json (generated by source-to-pass01-audit.mjs --dry-run).
 * Copies only image files (skips HTML, CSS, JS, docs, txt, etc.).
 * Deduplicates within the recovery set so the same hash is only copied once.
 * Flattens to one directory level: unclassified/{source-group}/{filename}
 *   HawaiiFruit. Net/avocado/images/foo.jpg → unclassified/avocado/foo.jpg
 *   original/2007 fruit shoot/foo.jpg      → unclassified/2007 fruit shoot/foo.jpg
 *
 * Usage:
 *   node scripts/recover-source-images.mjs --dry-run
 *   node scripts/recover-source-images.mjs
 */

import { readFileSync, existsSync, mkdirSync, copyFileSync } from 'fs';
import path from 'path';

const ROOT = path.resolve(import.meta.dirname, '..');
const DRY_RUN = process.argv.includes('--dry-run');

const SOURCE_DIR    = path.join(ROOT, 'content', 'source');
const REPORT_FILE   = path.join(ROOT, 'content', 'source-audit-report.json');
const DEST_ROOT     = path.join(ROOT, 'content', 'pass_01', 'unassigned', 'unclassified');
const CACHE_FILE    = path.join(ROOT, 'content', 'source-audit-hash-cache.json');

if (DRY_RUN) console.log('[DRY RUN] No files will be copied.\n');

// Extensions to recover (no html/css/js/eml/wav/xml)
const IMAGE_EXTS = new Set([
  '.jpg', '.jpeg', '.png', '.gif', '.bmp',
  '.tif', '.tiff', '.pct', '.psd', '.nef',
  '.heic', '.raw', '.cr2', '.arw', '.dng',
  '.pdf', '.doc', '.docx', '.ppt', '.pptx', '.xls', '.xlsx', '.txt',
]);

// ── Load report ───────────────────────────────────────────────────────────────

const report = JSON.parse(readFileSync(REPORT_FILE, 'utf-8'));
console.log(`Source audit report: ${report.not_in_pass01} files not in pass_01\n`);

// Load hash cache to dedup within recovery set
const cache = JSON.parse(readFileSync(CACHE_FILE, 'utf-8'));

// ── Filter to image files only ────────────────────────────────────────────────

const imageFiles = report.missing_files.filter(rel => {
  const ext = path.extname(rel).toLowerCase();
  return IMAGE_EXTS.has(ext);
});

console.log(`Image files to recover: ${imageFiles.length}`);

// ── Derive group dir from source-relative path ────────────────────────────────
// HawaiiFruit. Net/{dir}/...  → group = {dir}
// original/{dir}/...          → group = {dir}

function groupDir(sourceRel) {
  const parts = sourceRel.replace(/\\/g, '/').split('/');
  // parts[0] is "HawaiiFruit. Net" or "original"
  return parts[1] || parts[0]; // first meaningful subdir
}

// ── Safe filename collision resolver ─────────────────────────────────────────

function safeDestPath(dir, filename) {
  const ext = path.extname(filename);
  const base = path.basename(filename, ext);
  let candidate = path.join(dir, filename);
  if (!existsSync(candidate)) return candidate;
  for (let i = 1; i < 10000; i++) {
    candidate = path.join(dir, `${base}_${i}${ext}`);
    if (!existsSync(candidate)) return candidate;
  }
  throw new Error(`No free slot for ${filename} in ${dir}`);
}

// ── Dedup within recovery set (same hash → copy once) ────────────────────────

const seenHashes = new Set();
let skippedDupes = 0;
let skippedNoHash = 0;
let copied = 0;
let errors = 0;

// Count by group for summary
const byGroup = {};

for (const rel of imageFiles) {
  const absSource = path.join(SOURCE_DIR, rel.replace(/\//g, path.sep));
  const hash = cache[absSource];

  if (!hash || hash === 'ERROR' || hash === 'EMPTY') {
    skippedNoHash++;
    continue;
  }

  // Skip if we've already copied a file with this hash
  if (seenHashes.has(hash)) {
    skippedDupes++;
    continue;
  }
  seenHashes.add(hash);

  const group = groupDir(rel);
  const filename = path.basename(rel);
  const destDir = path.join(DEST_ROOT, group);

  byGroup[group] = (byGroup[group] || 0) + 1;

  if (!DRY_RUN) {
    try {
      mkdirSync(destDir, { recursive: true });
      const destAbs = safeDestPath(destDir, filename);
      copyFileSync(absSource, destAbs);
      copied++;
    } catch (err) {
      console.warn(`  WARN copy failed: ${rel}: ${err.message}`);
      errors++;
    }
  } else {
    copied++;
  }

  if (copied % 200 === 0) {
    process.stdout.write(`  ${copied} copied so far...\r`);
  }
}

console.log(`\n`);
console.log('By source group:');
Object.entries(byGroup).sort((a, b) => b[1] - a[1]).slice(0, 20).forEach(([g, n]) =>
  console.log(`  ${n.toString().padStart(5)}  ${g}`)
);
if (Object.keys(byGroup).length > 20) {
  console.log(`  ... and ${Object.keys(byGroup).length - 20} more groups`);
}

console.log(`\n══════════════════════════════════════════════════`);
console.log(`Copied:              ${copied}`);
console.log(`Skipped (dupes):     ${skippedDupes}`);
console.log(`Skipped (no hash):   ${skippedNoHash}`);
console.log(`Errors:              ${errors}`);
if (DRY_RUN) console.log('\n[DRY RUN] Re-run without --dry-run to apply.');
else console.log(`\nDone. Files are in pass_01/unassigned/unclassified/ — open /matches to review.`);
